import type { CalculatorSchemaV2 } from '@/types/calculator-schema-v2';
import { createValidatedValue, type CalculationResult } from '@/types/engineering';

export const mohrsCircleSchema: CalculatorSchemaV2 = {
    id: 'mohrs-circle',
    metadata: {
        title: "Mohr's Circle (Stress)",
        description: 'Calculate principal stresses and maximum shear stress.',
        category: 'mechanical',
        version: '1.0.0',
        author: 'AluCalc OS',
        lastUpdated: '2026-02-12',
        tags: ['stress', 'mechanics', 'transformation', 'mohr'],
        verifiedStandards: ['Mechanics of Materials']
    },
    documentation: {
        assumptions: [
            { id: 'plane-stress', text: 'Assumes plane stress state (sigma_z = 0)', impact: 'high' }
        ],
        standards: [
            { code: 'Standard Mechanics', title: 'Mohr Circle Transformation' }
        ],
        formulaLatex: '\\sigma_{1,2} = \\frac{\\sigma_x + \\sigma_y}{2} \\pm \\sqrt{\\left(\\frac{\\sigma_x - \\sigma_y}{2}\\right)^2 + \\tau_{xy}^2}'
    },
    inputs: [
        {
            key: 'sigmaX',
            label: 'Normal Stress X (σx)',
            description: 'Normal stress acting on the X face',
            unit: 'MPa',
            defaultValue: 50,
            validation: { required: true, step: 1 }
        },
        {
            key: 'sigmaY',
            label: 'Normal Stress Y (σy)',
            description: 'Normal stress acting on the Y face',
            unit: 'MPa',
            defaultValue: 10,
            validation: { required: true, step: 1 }
        },
        {
            key: 'tauXY',
            label: 'Shear Stress (τxy)',
            description: 'Shear stress acting on the X face',
            unit: 'MPa',
            defaultValue: 20,
            validation: { required: true, step: 1 }
        },
        {
            key: 'theta',
            label: 'Rotation Angle (θ)',
            description: 'Angle to rotate element',
            unit: 'deg',
            defaultValue: 0,
            validation: { min: -360, max: 360, required: true, step: 1 }
        }
    ],
    outputs: [
        {
            key: 'sigma1',
            label: 'Principal Stress 1 (σ₁)',
            unit: 'MPa',
            description: 'Maximum normal stress',
            formulaLatex: '\\sigma_1 = \\sigma_{avg} + R'
        },
        {
            key: 'sigma2',
            label: 'Principal Stress 2 (σ₂)',
            unit: 'MPa',
            description: 'Minimum normal stress',
            formulaLatex: '\\sigma_2 = \\sigma_{avg} - R'
        },
        {
            key: 'tauMax',
            label: 'Max Shear Stress (τmax)',
            unit: 'MPa',
            description: 'Maximum in-plane shear stress',
            formulaLatex: '\\tau_{max} = R'
        },
        {
            key: 'sigmaAvg',
            label: 'Average Stress (σavg)',
            unit: 'MPa',
            description: 'Center of Mohr\'s circle',
            formulaLatex: '\\sigma_{avg} = \\frac{\\sigma_x + \\sigma_y}{2}'
        },
        {
            key: 'thetaP',
            label: 'Principal Angle (θp)',
            unit: 'deg',
            description: 'Angle to principal planes',
            formulaLatex: '\\tan(2\\theta_p) = \\frac{2\\tau_{xy}}{\\sigma_x - \\sigma_y}'
        }
    ],
    calculationEngine: (inputs) => {
        const sx = inputs.sigmaX.value as number;
        const sy = inputs.sigmaY.value as number;
        const txy = inputs.tauXY.value as number;
        const theta = inputs.theta?.value as number || 0;

        const C = (sx + sy) / 2; // Center
        const R = Math.sqrt(Math.pow((sx - sy) / 2, 2) + Math.pow(txy, 2)); // Radius

        const s1 = C + R;
        const s2 = C - R;
        const tmax = R;

        // Principal angle calculation
        // atan2 returns -PI to PI
        let thetaRad = Math.atan2(2 * txy, sx - sy) / 2;
        let thetaP = (thetaRad * 180) / Math.PI;

        // Calculate stresses at rotated angle
        const thetaRotRad = (theta * Math.PI) / 180;
        const sx_rot = C + ((sx - sy) / 2) * Math.cos(2 * thetaRotRad) + txy * Math.sin(2 * thetaRotRad);
        const sy_rot = C - ((sx - sy) / 2) * Math.cos(2 * thetaRotRad) - txy * Math.sin(2 * thetaRotRad);
        const txy_rot = -((sx - sy) / 2) * Math.sin(2 * thetaRotRad) + txy * Math.cos(2 * thetaRotRad);

        return {
            outputs: {
                sigma1: createValidatedValue(s1, 'MPa', 'derived'),
                sigma2: createValidatedValue(s2, 'MPa', 'derived'),
                tauMax: createValidatedValue(tmax, 'MPa', 'derived'),
                sigmaAvg: createValidatedValue(C, 'MPa', 'derived'),
                thetaP: createValidatedValue(thetaP, 'deg', 'derived'),
                // Include rotated state for potential use
                sigmaX_rot: createValidatedValue(sx_rot, 'MPa', 'derived'),
                sigmaY_rot: createValidatedValue(sy_rot, 'MPa', 'derived'),
                tauXY_rot: createValidatedValue(txy_rot, 'MPa', 'derived')
            },
            verified: true,
            warnings: [],
            timestamp: Date.now()
        };
    },
    visualization: {
        type: 'svg-parametric',
        render: (result: CalculationResult, inputs: Record<string, number>) => {
            if (!result || !result.outputs) return null;

            const s1 = result.outputs.sigma1.value as number;
            const s2 = result.outputs.sigma2.value as number;
            const tmax = result.outputs.tauMax.value as number;
            const C = result.outputs.sigmaAvg.value as number;
            const sx = inputs['sigmaX'];
            const txy = inputs['tauXY'];
            const sy = inputs['sigmaY'];

            // Scaling
            // Determine viewing window: min(s2, 0) to max(s1, 0) plus margin
            const maxVal = Math.max(Math.abs(s1), Math.abs(s2), Math.abs(tmax));
            const viewRadius = maxVal * 1.2 || 10; // Default if 0

            // Transform coordinates to SVG (0,0 at center 150,150)
            const w = 300; const h = 300;
            const cx = 150; const cy = 150;
            const scale = (w / 2) / viewRadius * 0.8; // 80% usage

            const mapX = (val: number) => cx + val * scale;
            const mapY = (val: number) => cy - val * scale; // Positive shear up (or down, standard mechanics uses positive down for CW)
            // Convention: Standard Math (Positive Y Up in diagram, but SVG Y is Down)
            // Let's stick to standard graph: +Y (Shear) Up.

            const r_px = tmax * scale;
            const c_px = mapX(C);

            const sx_px = mapX(sx);
            const txy_px = mapY(txy);

            // Sy point is diametrically opposite
            const sy_px = mapX(sy || 0);
            const tyx_px = mapY(-(txy || 0));

            return (
                <svg viewBox={`0 0 ${w} ${h}`} width="100%" height="100%">
                    {/* Grid / Axes */}
                    <line x1="0" y1={cy} x2={w} y2={cy} stroke="#334155" strokeWidth="1" />
                    <line x1={cx} y1="0" x2={cx} y2={h} stroke="#334155" strokeWidth="1" />

                    {/* Circle */}
                    <circle cx={c_px} cy={cy} r={r_px} fill="rgba(0, 229, 255, 0.05)" stroke="#00e5ff" strokeWidth="2" />

                    {/* X-Face Point (Stress State) */}
                    <line x1={c_px} y1={cy} x2={sx_px} y2={txy_px} stroke="#94a3b8" strokeDasharray="4,4" />
                    <circle cx={sx_px} cy={txy_px} r="4" fill="#ef4444" />
                    <text x={sx_px + 5} y={txy_px - 5} fill="#ef4444" fontSize="10">X</text>

                    {/* Y-Face Point */}
                    <line x1={c_px} y1={cy} x2={sy_px} y2={tyx_px} stroke="#94a3b8" strokeDasharray="4,4" />
                    <circle cx={sy_px} cy={tyx_px} r="4" fill="#3b82f6" />
                    <text x={sy_px + 5} y={tyx_px - 5} fill="#3b82f6" fontSize="10">Y</text>

                    {/* Diameter Line */}
                    <line x1={sx_px} y1={txy_px} x2={sy_px} y2={tyx_px} stroke="#cbd5e1" strokeWidth="1" opacity="0.5" />

                    {/* Principal Stresses */}
                    <circle cx={mapX(s1)} cy={cy} r="3" fill="#10b981" />
                    <text x={mapX(s1) + 5} y={cy - 5} fill="#10b981" fontSize="10">σ1</text>

                    <circle cx={mapX(s2)} cy={cy} r="3" fill="#10b981" />
                    <text x={mapX(s2) - 15} y={cy - 5} fill="#10b981" fontSize="10">σ2</text>

                    {/* Labels */}
                    <text x="10" y="20" fill="#94a3b8" fontSize="10">τ (Shear)</text>
                    <text x={w - 20} y={cy - 5} fill="#94a3b8" fontSize="10">σ</text>

                    <text x="10" y={h - 10} fill="#64748b" fontSize="10">
                        C: {C.toFixed(1)} MPa, R: {tmax.toFixed(1)} MPa
                    </text>
                </svg>
            );
        }
    }
};
