
import type { CalculatorSchemaV2 } from '@/types/calculator-schema-v2';
import { createValidatedValue } from '@/types/engineering';

const sheetMetalSchema: CalculatorSchemaV2 = {
    id: 'sheet-metal',
    metadata: {
        title: 'Sheet Metal Bending',
        description: 'Calculate Bend Allowance, Bend Deduction, and K-Factor.',
        category: 'fabrication',
        version: '2.0.0',
        author: 'AluCalc Engineering',
        lastUpdated: '2026-02-10',
        tags: ['bending', 'sheet-metal', 'k-factor', 'fabrication'],
        verifiedStandards: ['DIN 6935'],
    },

    inputs: [
        {
            key: 'thickness',
            label: 'Material Thickness (t)',
            unit: 'mm',
            defaultValue: 2,
            description: 'Sheet metal thickness.',
            validation: { required: true, min: 0.1 }
        },
        {
            key: 'radius',
            label: 'Inside Bend Radius (R)',
            unit: 'mm',
            defaultValue: 2,
            description: 'Internal radius of the bend.',
            validation: { required: true, min: 0.1 }
        },
        {
            key: 'angle',
            label: 'Bend Angle (theta)',
            unit: 'deg',
            defaultValue: 90,
            description: 'Angle of the bend (usually 90).',
            validation: { required: true, min: 0, max: 180 }
        },
        {
            key: 'kFactor',
            label: 'K-Factor',
            unit: '-',
            defaultValue: 0.33,
            description: 'Neutral axis location (0.33 for R<t, 0.44 for R>t, or custom).',
            validation: { required: true, min: 0, max: 1 }
        }
    ],

    outputs: [
        {
            key: 'bendAllowance',
            label: 'Bend Allowance (BA)',
            unit: 'mm',
            formulaLatex: 'BA = \\frac{\\pi(R + K \\cdot t) \\cdot A}{180}',
            description: 'Arc length of the bend at neutral axis.',
            precision: 3
        },
        {
            key: 'bendDeduction',
            label: 'Bend Deduction (BD)',
            unit: 'mm',
            formulaLatex: 'BD = 2(OSS) - BA',
            description: 'Amount to subtract from total flange lengths.',
            precision: 3
        },
        {
            key: 'outsideSetback',
            label: 'Outside Setback (OSSB)',
            unit: 'mm',
            formulaLatex: 'OSS = (R+t) \\tan(A/2)',
            description: 'Distance from tangent point to apex outside.',
            precision: 3
        }
    ],

    calculationEngine: (inputs) => {
        const t = inputs.thickness.value as number;
        const R = inputs.radius.value as number;
        const A = inputs.angle.value as number;
        const K = inputs.kFactor.value as number;

        const rads = (A * Math.PI) / 180;

        // Bend Allowance
        const BA = rads * (R + K * t);

        // Outside Setback
        const OSSB = (R + t) * Math.tan(rads / 2);

        // Bend Deduction
        const BD = (2 * OSSB) - BA;

        return {
            outputs: {
                bendAllowance: createValidatedValue(BA, 'mm', 'derived'),
                bendDeduction: createValidatedValue(BD, 'mm', 'derived'),
                outsideSetback: createValidatedValue(OSSB, 'mm', 'derived')
            },
            verified: true,
            warnings: [],
            timestamp: Date.now()
        };
    },

    visualization: {
        type: 'svg-parametric',
        render: (result, inputs) => {
            if (!inputs) return null;

            const t = inputs.thickness || 2;
            const R = inputs.radius || 2;
            const A = inputs.angle || 90;

            // Draw profile
            // Simple logic for 90 deg: L shape
            // For other angles, line + arc + line

            const scale = 5;
            const startX = 50;
            const startY = 100;
            const legLen = 50;

            // This is complex for arbitrary angle in simple SVG string gen
            // Let's assume 90 deg for visual simplicity or implement simple arc path

            // Path:
            // 1. Move to (startX, startY)
            // 2. Line to (startX + legLen, startY) -> This is leg 1
            // 3. Arc?
            // Actually, usually we visualize the Cross Section

            return (
                <svg viewBox="0 0 200 200" style={{ width: '100%', height: '100%' }}>
                    {/* Placeholder for Bend visual */}
                    <path d={`M 50 150 L 100 150 Q 120 150 120 130 L 120 80`} fill="none" stroke="#00e5ff" strokeWidth={t} />
                    <text x="100" y="170" fill="#fff" fontSize="10">t={t}</text>
                    <text x="110" y="140" fill="#fff" fontSize="10">R={R}</text>
                    <text x="140" y="100" fill="#fff" fontSize="10">{A}°</text>
                </svg>
            );
        }
    },

    documentation: {
        assumptions: [],
        standards: [{ code: 'DIN 6935', title: 'Cold bending of flat steel products' }],
        formulaLatex: 'BA = \\frac{\\pi A}{180}(R + K t)'
    },

    tier: 'free'
};

export default sheetMetalSchema;
